#include <cstdio>
#include <fstream>

#include "engine/engine.h"
#include "pcapio/pcap_reader.h"
#include "test.h"

using namespace avb;

namespace {

std::string tmpFile(const std::string& name) {
    return "build/" + name;
}

void writeFile(const std::string& path, const std::string& bytes) {
    std::ofstream f(path, std::ios::binary | std::ios::trunc);
    f.write(bytes.data(), (std::streamsize)bytes.size());
}

void put32le(std::string& s, uint32_t v) {
    s.push_back((char)(v & 0xff));
    s.push_back((char)((v >> 8) & 0xff));
    s.push_back((char)((v >> 16) & 0xff));
    s.push_back((char)((v >> 24) & 0xff));
}
void put16le(std::string& s, uint16_t v) {
    s.push_back((char)(v & 0xff));
    s.push_back((char)((v >> 8) & 0xff));
}

std::shared_ptr<Session> runSession(const std::string& pcapPath) {
    Engine engine;
    auto s = std::make_shared<Session>();
    s->id = "t1";
    s->name = pcapPath;
    s->pcapFilePath = pcapPath;
    engine.start(s);
    engine.drain();
    return s;
}

size_t countTransitions(const Session& s, const std::string& needle) {
    size_t n = 0;
    for (auto& e : s.events)
        if (e.kind == Kind::Transition && e.summary.find(needle) != std::string::npos)
            ++n;
    return n;
}

} // namespace

TEST(pcap_classic_microseconds) {
    std::string f;
    put32le(f, 0xa1b2c3d4);
    put16le(f, 2);
    put16le(f, 4);
    put32le(f, 0);
    put32le(f, 0);
    put32le(f, 262144);
    put32le(f, 1); // Ethernet
    // one 60-byte packet at t=1.5
    put32le(f, 1700000001);
    put32le(f, 500000);
    put32le(f, 60);
    put32le(f, 60);
    f.append(60, '\0');
    writeFile(tmpFile("t_classic.pcap"), f);

    PcapFile p;
    std::string err;
    CHECK(p.open(tmpFile("t_classic.pcap"), err));
    CHECK_EQ(p.packets().size(), (size_t)1);
    CHECK_EQ(p.packets()[0].tsNanos, 1700000001500000000ull);
    CHECK_EQ(p.packets()[0].caplen, 60u);
}

TEST(pcap_rejects_bad_input) {
    PcapFile p;
    std::string err;
    writeFile(tmpFile("t_bad.pcap"), "this is not a capture at all");
    CHECK(!p.open(tmpFile("t_bad.pcap"), err));
    CHECK(!err.empty());

    // Non-Ethernet link type is refused (v1) and named in the error.
    std::string f;
    put32le(f, 0xa1b2c3d4);
    put16le(f, 2);
    put16le(f, 4);
    put32le(f, 0);
    put32le(f, 0);
    put32le(f, 262144);
    put32le(f, 113); // LINKTYPE_LINUX_SLL, "any" interface
    writeFile(tmpFile("t_sll.pcap"), f);
    PcapFile p2;
    CHECK(!p2.open(tmpFile("t_sll.pcap"), err));
    CHECK(err.find("Linux cooked/SLL") != std::string::npos);
    CHECK(err.find("\"any\"") != std::string::npos);
}

TEST(pcapng_mpacket_preamble_stripped) {
    std::string f;
    // SHB
    put32le(f, 0x0a0d0d0a);
    put32le(f, 28);
    put32le(f, 0x1a2b3c4d);
    put16le(f, 1);
    put16le(f, 0);
    put32le(f, 0xffffffff);
    put32le(f, 0xffffffff);
    put32le(f, 28);
    // IDB: 802.3br mPacket (ProfiShark preamble mode)
    put32le(f, 1);
    put32le(f, 20);
    put16le(f, 274);
    put16le(f, 0);
    put32le(f, 0);
    put32le(f, 20);
    // EPB: preamble(7×0x55) + SFD(0xD5) + 60-byte frame + 4-byte FCS
    const uint32_t caplen = 8 + 60 + 4;
    put32le(f, 6);
    put32le(f, 32 + caplen);
    put32le(f, 0);
    put32le(f, 0);
    put32le(f, 1000);
    put32le(f, caplen);
    put32le(f, caplen);
    f.append(7, '\x55');
    f.push_back('\xd5');
    f.push_back('\x01'); // frame starts with the MSRP multicast dst
    f.append(59, '\0');
    f.append(4, '\xAA'); // FCS
    put32le(f, 32 + caplen);
    writeFile(tmpFile("t_mpacket.pcapng"), f);

    PcapFile p;
    std::string err;
    CHECK(p.open(tmpFile("t_mpacket.pcapng"), err));
    CHECK_EQ(err, std::string());
    CHECK_EQ(p.packets().size(), (size_t)1);
    CHECK_EQ(p.packets()[0].caplen, 64u);       // preamble+SFD gone
    CHECK_EQ(p.packetData(0)[0], (uint8_t)0x01); // frame starts at dst MAC
}

TEST(pcapng_names_non_ethernet_linktype) {
    std::string f;
    // SHB
    put32le(f, 0x0a0d0d0a);
    put32le(f, 28);
    put32le(f, 0x1a2b3c4d);
    put16le(f, 1);
    put16le(f, 0);
    put32le(f, 0xffffffff);
    put32le(f, 0xffffffff);
    put32le(f, 28);
    // IDB: Linux SLL2 (captured on "any")
    put32le(f, 1);
    put32le(f, 20);
    put16le(f, 276);
    put16le(f, 0);
    put32le(f, 0);
    put32le(f, 20);
    writeFile(tmpFile("t_sll2.pcapng"), f);

    PcapFile p;
    std::string err;
    CHECK(!p.open(tmpFile("t_sll2.pcapng"), err));
    CHECK(err.find("no Ethernet interface") != std::string::npos);
    CHECK(err.find("SLL2") != std::string::npos);
}

TEST(pcapng_basic) {
    std::string f;
    // SHB
    put32le(f, 0x0a0d0d0a);
    put32le(f, 28);
    put32le(f, 0x1a2b3c4d);
    put16le(f, 1);
    put16le(f, 0);
    put32le(f, 0xffffffff);
    put32le(f, 0xffffffff);
    put32le(f, 28);
    // IDB: Ethernet, default µs resolution
    put32le(f, 1);
    put32le(f, 20);
    put16le(f, 1);
    put16le(f, 0);
    put32le(f, 0);
    put32le(f, 20);
    // EPB with one 64-byte packet
    uint64_t tsUs = 1700000002000123ull;
    put32le(f, 6);
    put32le(f, 32 + 64);
    put32le(f, 0);
    put32le(f, (uint32_t)(tsUs >> 32));
    put32le(f, (uint32_t)tsUs);
    put32le(f, 64);
    put32le(f, 64);
    f.append(64, '\0');
    put32le(f, 32 + 64);
    writeFile(tmpFile("t_ng.pcapng"), f);

    PcapFile p;
    std::string err;
    CHECK(p.open(tmpFile("t_ng.pcapng"), err));
    CHECK_EQ(err, std::string());
    CHECK_EQ(p.packets().size(), (size_t)1);
    CHECK_EQ(p.packets()[0].tsNanos, tsUs * 1000);
}

// ---- golden traces (TV-1) -------------------------------------------------

TEST(golden_msrp_basic) {
    auto s = runSession("testdata/msrp_basic.pcap");
    CHECK_EQ(s->status.load(), (int)Session::Done);
    CHECK_EQ(s->decodeErrors.load(), (uint64_t)0);
    CHECK_EQ(s->packets.load(), (uint64_t)7);
    CHECK(countTransitions(*s, "-> PENDING") >= 1);
    CHECK(countTransitions(*s, "-> ESTABLISHED") == 1);
    CHECK(countTransitions(*s, "-> WITHDRAWN") == 1);
    std::string st = s->stateJson();
    CHECK(st.find("\"state\":\"WITHDRAWN\"") != std::string::npos);
    CHECK(st.find("\"vid\":2") != std::string::npos);
    CHECK(st.find("\"class_id\":6") != std::string::npos);
}

