TEST(golden_milan_binding) {
    auto s = runSession("testdata/milan_binding.pcap");
    CHECK_EQ(s->decodeErrors.load(), (uint64_t)0);
    // Full Milan §5.5.3 lifecycle as observed on the wire.
    CHECK(countTransitions(*s, "-> PRB_W_DELAY") == 2); // bind + rediscovery
    CHECK(countTransitions(*s, "-> PRB_W_RESP ") >= 2);
    CHECK(countTransitions(*s, "-> SETTLED_NO_RSV") == 2);
    CHECK(countTransitions(*s, "-> SETTLED_RSV_OK") == 2);
    CHECK(countTransitions(*s, "-> PRB_W_AVAIL") == 1);  // talker departed
    CHECK(countTransitions(*s, "-> UNBOUND") == 1);
    std::string st = s->stateJson();
    CHECK(st.find("\"probing_status\":\"PROBING_DISABLED\"") != std::string::npos);
    CHECK(st.find("\"milan_talkers\"") != std::string::npos);
    CHECK(st.find("\"probes_received\":2") != std::string::npos);
}

TEST(golden_malformed_never_crashes) {
    auto s = runSession("testdata/malformed.pcap");
    CHECK_EQ(s->status.load(), (int)Session::Done);
    CHECK_EQ(s->decodeErrors.load(), (uint64_t)7);
    // The valid trailing packet still decodes (PA-5).
    bool sawValid = false;
    for (auto& e : s->events)
        if (e.kind == Kind::Packet && e.type == "ENTITY_AVAILABLE") sawValid = true;
    CHECK(sawValid);
}

TEST(golden_milan_scenario) {
    auto s = runSession("testdata/milan_scenario.pcap");
    CHECK_EQ(s->status.load(), (int)Session::Done);
    CHECK_EQ(s->decodeErrors.load(), (uint64_t)0);
    CHECK_EQ(s->packets.load(), (uint64_t)36);

    std::string st = s->stateJson();
    // PA-6: entities named from AEM enumeration.
    CHECK(st.find("\"name\":\"Stage Box FOH\"") != std::string::npos);
    CHECK(st.find("\"name\":\"Monitor Desk\"") != std::string::npos);
    // Full lifecycle ends disconnected/withdrawn/departing.
    CHECK(st.find("\"state\":\"DISCONNECTED\"") != std::string::npos);
    CHECK(st.find("\"state\":\"WITHDRAWN\"") != std::string::npos);
    CHECK(st.find("\"state\":\"DEPARTING\"") != std::string::npos);
    CHECK(st.find("\"state\":\"ACQUIRED\"") != std::string::npos);
    // The connection went through CONNECTED on the way.
    CHECK(countTransitions(*s, "-> CONNECTED") == 1);
    // Events are strictly ordered (CO-3).
    double last = -1;
    for (auto& e : s->events) {
        CHECK(e.ts >= last);
        last = e.ts;
    }
}
